head.script:
scwin.editYn ="N";//변경정보 처리후 재조회시 체크하기 위한 처리.
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
	if (scwin.editYn =="N"){ //저장처리후에는 체크하지 않기 위한 방어코드
        if ( ds_bank.getModifiedIndex().length > 0 ) {
            if (await $c.win.confirm(MSG_CM_CRM_005) ) {
                $c.sbm.execute(sbm_retrieve);
            }
        }
        else {
            $c.sbm.execute(sbm_retrieve);
        }
    }else{
        $c.sbm.execute(sbm_retrieve);        
    }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save =  async function (e) {
    if(ds_bank.getModifiedIndex().length==0){
         $c.win.alert($c.data.getMessage(MSG_CM_ERR_001,"은행코드등록"));
         return false;
    }

    let ret = await $c.gus.cfValidate([gr_bankList]);

    if (ret) {
        scwin.editYn ="Y";

        let validArry = [
        {id:"bankCd", name: "은행코드",key:true}
        ];
        let gridName = "은행코드등록";
        if(!await $c.gus.cfValidateGrid(gr_bankList, null, null, validArry, gridName)){
            return false;
        }

        if(await $c.win.confirm(MSG_CM_CRM_001)) {
            $c.sbm.execute(sbm_saveBank);
        }
    }else{
        scwin.editYn ="N";
    }
};

//-------------------------------------------------------------------------
// 행추가
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
    $c.data.insertRow($p.getComponentById("gr_bankList"));
};

//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_UndoAll = function () {
    $c.data.undoRow(ds_bank, "Y");
};

//-------------------------------------------------------------------------
// 신규 은행코드 삭제시 수행 (DB에 저장된 은행코드는 삭제 할 수 없음)
//-------------------------------------------------------------------------
scwin.f_Delete = function() {
    if (ds_bank.getRowStatus(ds_bank.getRowPosition() )!="C"){
        $c.gus.cfAlertMsg("저장 되어 있는 은행코드는 삭제를 하실 수 없습니다.");
		return;
    }
    ds_bank.removeRow(ds_bank.getRowPosition()); //C일때 다른경우는 deleteRow
};

//-------------------------------------------------------------------------
// 조회결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = function(e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    scwin.editYn ="N";

    if(e.responseJSON.GAUCE) {
        ds_bank.setJSON(e.responseJSON.GAUCE);

        if (ds_bank.getRowCount()==0){
            $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        }else{
            $c.gus.cfGoPrevPosition(gr_bankList, 0); //첫번째 row 포지션이동
        }
    }
    // 조회된 건수를 Grid 왼쪽 하단에 표시한다.
    tbx_totalRows.setValue($c.gus.cfInsertComma(ds_bank.getRowCount()));

}; 

//-------------------------------------------------------------------------
// 저장결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_saveBank_submitdone = async function() {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.f_Retrieve();
};
